#include <bits/stdc++.h>
using namespace std;
long long n[100000010];
int main(){
	long long a,b;
	cin>>a>>b;
	for(long long i=a;i<=b;i++){
		if(i%2==0){
			continue;
		}
		if(i%3==0){
			continue;
		}
		bool shw=1;
		string str = to_string(i);
		int left = 0;
		int right = str.length()-1;
		while (left < right) {
			if (str[left] != str[right]) {
				shw = 0;
			}
			left++;
			right--;
		}
		

		if(shw){
			long long k2=i;
			bool szs=1;
			for(long long u=3;u<=sqrt(k2);u+=2){
				if(k2%u==0){
					szs=0;
					break;
				}
			}
			if(szs==1){
				cout<<i<<"\n";
			}
		}
	}	
	return 0;
}
